and status = #{status}
order by appointment_id desc

select appointment_id, appointment_no, user_id, customer_name, customer_phone, service_type,
       preferred_date, preferred_time, address, remark, product_id, region_id, status,
       assigned_to, admin_note, create_time, update_time
from bh_appointment
where user_id = #{userId}
  and appointment_id = #{appointmentId}
